#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int X; scanf("%d",&X);
        int fine = (X<=70)?0:(X<=100)?500:2000;
        printf("%d\n",fine);
    }
    return 0;
}

