code.Python3:
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        x = int(data[i])
        if x <= 70:
            out.append('0')
        elif x <= 100:
            out.append('500')
        else:
            out.append('2000')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

